1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	const basePremiumFor = (items: { type: string }[]): number =>
10	  items.length === 0 ? 0 : BASE_PREMIUMS[items[0].type];
11	
12	export const runScenario = (scenario: any): unknown => {
13	  const base = basePremiumFor(scenario.steps[0].items);
14	  const premium = base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE;
15	  return { results: [{ premium }] };
16	};
